package com.agmsolutions.fabrick_test.Model.dto;import com.fasterxml.jackson.annotation.JsonFormat;import com.fasterxml.jackson.annotation.JsonInclude;import com.fasterxml.jackson.annotation.JsonProperty;import jakarta.validation.Valid;import jakarta.validation.constraints.FutureOrPresent;import jakarta.validation.constraints.NotBlank;import jakarta.validation.constraints.NotNull;import jakarta.validation.constraints.Positive;import lombok.AllArgsConstructor;import lombok.Builder;import lombok.Data;import lombok.NoArgsConstructor;import java.math.BigDecimal;import java.time.LocalDate;@Data@NoArgsConstructor@AllArgsConstructor@Builder@JsonInclude(JsonInclude.Include.NON_NULL)public class MoneyTransferBodyDto {        @NotNull(message = "creditore obbligatorio")    @Valid    private CreditorDto creditor;        @NotNull(message = "data esecuzione obbligatoria")    @FutureOrPresent(message = "La data di esecuzione non può essere nel passato")    @JsonFormat(pattern = "yyyy-MM-dd")    private LocalDate executionDate;        private String uri;        @NotBlank(message = "descrizione obbligatoria")    private String description;        @NotNull(message = "importo obbligatorio")    @Positive(message = "l'importo deve essere positivo")    private BigDecimal amount;    @NotBlank(message = "valuta obbligatoria")    private String currency;        @JsonProperty("isUrgent")    private Boolean isUrgent;        @JsonProperty("isInstant")    private Boolean isInstant;        private String feeType;        private String feeAccountId;        private TaxReliefDto taxRelief;    }